  "outreach_draft": "string — 3-sentence email/call opener",
  "social_intelligence": "string — events, showcases, LinkedIn signals, recent news Kevin can leverage",
  "whatsapp_brief": "string — Aidan's consolidated CEO brief, 400 chars max, lead with source URL and open lane"
}`;

const userPrompt = `SCOUT REPORT:\n${input.aiOutput.substring(0,3000)}\n\n${input.enrichmentContext||''}\n\nOrg identified: ${input.orgName}\nSource URLs found: ${(input.sourceUrls||[]).join(', ')}\n\nProduce the JSON synthesis now.`;

const rb = JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 2000, system: systemPrompt, messages: [{ role: 'user', content: userPrompt }] });

const result = await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(rb) }
  }, function(res) { let d=''; res.on('data',function(c){d+=c;}); res.on('end',function(){resolve({status:res.statusCode,body:d});}); });
  req.on('error', reject); req.write(rb); req.end();
});

let intel = {};
try {
  const raw = JSON.parse(result.body).content[0].text;
  const clean = raw.replace(/^```json\s*/,'').replace(/^```\s*/,'').replace(/\s*```$/,'').trim();
  intel = JSON.parse(clean);
} catch(e) {
  intel = {
    title: input.orgName || input.query,
    organization: input.orgName || 'Unknown',
    classification: 'VALIDATE_SOURCE',
    evidence_quality: 'SOURCE_GAP',
    why_this_matters: 'Parse error — see raw report',
    recommended_next_action: 'Review raw Scout report',
    whatsapp_brief: 'Scout report complete — synthesis failed. Check raw file.'
  };
}

// Write to Supabase pipeline table
let pipelineId = null;
let pipelineLogged = false;
if (SUPABASE_URL && SUPABASE_KEY && intel.title) {
  try {
    const record = {
      title: intel.title,
      entity: intel.entity_fit || 'FP',
      opportunity_type: intel.opportunity_type || 'contract',
      vertical: intel.vertical || null,
      fit_score: intel.fit_score || null,
      source_url: intel.source_url || null,
      source_title: intel.source_title || null,
      source_platform: intel.source_platform || null,
      contact_name: intel.contact_name !== 'UNCONFIRMED' ? intel.contact_name : null,
      contact_title: intel.contact_title || null,
      contact_email: intel.contact_email || null,
      contact_phone: intel.contact_phone || null,
      organization: intel.organization || null,
      program_office: intel.program_office || null,
      application_portal: intel.application_portal || null,
      eligibility_notes: intel.eligibility_notes || null,
      why_this_matters: intel.why_this_matters || null,
      why_kai_fits: intel.why_kai_fits || null,
      recommended_next_action: intel.recommended_next_action || null,
      pursuit_steps: intel.pursuit_steps ? JSON.stringify(intel.pursuit_steps) : null,
      risks: intel.risks ? JSON.stringify(intel.risks) : null,
      blockers: intel.blockers ? JSON.stringify(intel.blockers) : null,
      confidence_score: intel.confidence_score || null,
      follow_up_script: intel.follow_up_script || null,
      outreach_draft: intel.outreach_draft || null,
      classification: intel.classification || 'VALIDATE_SOURCE',
      status: 'pursuing',
      created_by_agent: 'Scout v5',
      last_activity_at: new Date().toISOString(),
      source: 'scout_v5',
      kevin_note: intel.social_intelligence ? intel.social_intelligence.substring(0,500) : null
    };
    const body = JSON.stringify(record);
    const r = await new Promise(function(resolve, reject) {
      const req = https.request({
        hostname: SUPABASE_URL, port: 443, path: '/rest/v1/pipeline', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Prefer': 'return=representation', 'Content-Length': Buffer.byteLength(body) }
      }, function(res) { let d=''; res.on('data',function(c){d+=c;}); res.on('end',function(){resolve({status:res.statusCode,body:d});}); });
      req.on('error', reject); req.write(body); req.end();
    });
    if (r.status === 201 || r.status === 200) {
      pipelineLogged = true;
      try { pipelineId = JSON.parse(r.body)[0]?.id || null; } catch(e) {}
    }
  } catch(e) {}
}

return [{ json: Object.assign({}, input, {
  intel: intel,
  pipelineId: pipelineId,
  pipelineLogged: pipelineLogged,
  whatsappBrief: intel.whatsapp_brief || '',
  classification: intel.classification || 'VALIDATE_SOURCE',
  priorityScore: intel.priority_score || 0
}) }];

// AIDAN CALLBACK v5.1 — CEO Brief Delivery
// Delivers consolidated ranked brief in Aidan's voice
// Source URL first. Social intelligence. Outreach script. No fluff.
const http = require('http');
const fs = require('fs');
const input = $input.first().json;
const intel = input.intel || {};

const classification = intel.classification || 'VALIDATE_SOURCE';
const classIcon = {
  'PURSUE_NOW': '🔥',
  'CONTACT_READY': '📞',
  'VALIDATE_SOURCE': '🔍',
  'WATCHLIST': '👁',
  'BLOCKED': '🔴',
  'ARCHIVE': '📁'
}[classification] || '📋';

const fitScore = intel.fit_score || input.fitScore || null;
const priorityScore = intel.priority_score || null;
const evidenceQuality = intel.evidence_quality || 'LOW';
const evidenceIcon = { 'HIGH': '✅', 'MEDIUM': '⚠️', 'LOW': '❌', 'SOURCE_GAP': '⚠️ SOURCE GAP' }[evidenceQuality] || '❓';

// Build CEO brief
let brief = '';

// Header
brief += classIcon + ' ' + classification + ' — ' + (intel.title || input.orgName || input.query) + '\n';
brief += '━━━━━━━━━━━━━━━━━━━━━━\n';

// Source — most important
if (intel.source_url) {
  brief += '🌐 SOURCE: ' + intel.source_url + '\n';
}
if (intel.source_title) {
  brief += '   ' + intel.source_title + '\n';
}
brief += evidenceIcon + ' Evidence: ' + evidenceQuality + '\n';

// Scores
brief += '\n';
if (fitScore) brief += '📊 Fit: ' + fitScore + '/100';
if (priorityScore) brief += ' | Priority: ' + priorityScore + '/100';
if (intel.revenue_potential) brief += ' | 💰 ' + intel.revenue_potential;
brief += '\n';
if (intel.deadline) brief += '⏰ Deadline: ' + intel.deadline + '\n';

// Entity + vertical
brief += '🏢 Entity: ' + (intel.entity_fit||'FP') + ' | ' + (intel.vertical||'See report') + '\n';

// Why it matters
if (intel.why_this_matters) {
  brief += '\n💡 WHY THIS MATTERS:\n' + intel.why_this_matters + '\n';
}
if (intel.why_kai_fits) {
  brief += '\n🎯 KAI FIT:\n' + intel.why_kai_fits + '\n';
}

// Social intelligence — events, showcases, LinkedIn signals
if (intel.social_intelligence) {
  brief += '\n🔎 INTEL:\n' + intel.social_intelligence + '\n';
}

// Contact path
brief += '\n📋 CONTACT PATH:\n';
if (intel.contact_name && intel.contact_name !== 'UNCONFIRMED') {
  brief += '   ' + intel.contact_name + (intel.contact_title ? ' — ' + intel.contact_title : '') + '\n';
}
if (intel.contact_phone) brief += '   📞 ' + intel.contact_phone + '\n';
if (intel.contact_email) brief += '   📧 ' + intel.contact_email + '\n';
if (intel.application_portal) brief += '   🌐 ' + intel.application_portal + '\n';

// Next action
if (intel.recommended_next_action) {
  brief += '\n⚡ NEXT ACTION:\n' + intel.recommended_next_action + '\n';
}

// Pursuit steps
if (intel.pursuit_steps && intel.pursuit_steps.length) {
  brief += '\n📌 PURSUIT STEPS:\n';
  intel.pursuit_steps.forEach(function(s, i) { brief += (i+1) + '. ' + s + '\n'; });
}

// Outreach script
if (intel.follow_up_script) {
  brief += '\n💬 OPENING LINE:\n"' + intel.follow_up_script + '"\n';
}

// Risks
if (intel.risks && intel.risks.length) {
  brief += '\n⚠️ RISKS: ' + intel.risks.join(' | ') + '\n';
}
if (intel.blockers && intel.blockers.length) {
  brief += '🔴 BLOCKERS: ' + intel.blockers.join(' | ') + '\n';
}

// Pipeline status
const dbIcon = input.pipelineLogged ? '✅' : '⚠️';
brief += '\n' + dbIcon + ' Pipeline: ' + (input.pipelineLogged ? 'Saved to dashboard' : 'Log failed — check Supabase') + '\n';
brief += '📄 Full report: http://localhost:3030/Aidan_Outputs/Scout/' + (input.filename||'') + '\n';

// Split for WhatsApp 3800 char limit
const chunks = [];
for (let i = 0; i < brief.length; i += 3800) chunks.push(brief.substring(i, i+3800));

for (let i = 0; i < chunks.length; i++) {
  const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: chunks[i] } });
  const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
  await new Promise(function(r) { const req = http.request(opts, function(res) { res.on('data',function(){}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });
  if (chunks.length > 1) await new Promise(function(r) { setTimeout(r, 1200); });
}

// Write last success timestamp
try {
  fs.mkdirSync('/data/Aidan_Outputs/Scout', { recursive: true });
  if (input.pipelineLogged) fs.writeFileSync('/data/Aidan_Outputs/Scout/.supabase_last_success', new Date().toISOString(), 'utf8');
} catch(e) {}

// Aidan callback
const cbBody = JSON.stringify({ agent: 'Scout', version: 'v5.1', summary: brief.substring(0,500), fitScore: fitScore, classification: classification, pipelineLogged: input.pipelineLogged, timestamp: new Date().toISOString() });
const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
const cbReq = http.request(cbOpts, function(res) { res.on('data',function(){}); res.on('end',function(){}); }); cbReq.on('error',function(){}); cbReq.write(cbBody); cbReq.end();

return [{ json: { success: true, agent: 'Scout', version: 'v5.1', classification, fitScore, pipelineLogged: input.pipelineLogged } }];
